<?php require_once __DIR__.'/../includes/app-layout.php'; bos_require_admin(); $wallet=bos_page_start('Admin','Creator Tasks','Post and approve paid work.'); $msg=''; if($_SERVER['REQUEST_METHOD']==='POST'&&bos_verify_csrf($_POST['csrf']??null)){try{$s=beyond_db()->prepare("INSERT INTO creator_tasks(title,description,category,reward_type,reward_bits,reward_cash,currency,status,created_by,created_at) VALUES(?,?,?,?,?,?,?,'open',?,NOW())");$s->execute([trim($_POST['title']),trim($_POST['description']),trim($_POST['category']),$_POST['reward_type'],(int)($_POST['reward_bits']??0),(float)($_POST['reward_cash']??0),'USD',bos_current_user_id()]);$msg='Task published.';}catch(Throwable $e){$msg='Import the 2.1 migration before publishing tasks.';}} ?><main class="bos-main"><section class="bos-hero"><span class="bos-kicker">Admin</span><h1>Creator Tasks</h1><p>Offer approved work in promotional content, gaming, design, development, translation and testing.</p></section><section class="bos-section"><?php if($msg):?><div class="bos-notice"><?=e($msg)?></div><?php endif;?><form method="post" class="bos-form"><input type="hidden" name="csrf" value="<?=e(bos_csrf_token())?>"><label>Title<input name="title" required></label><label>Category<input name="category" required placeholder="Social media"></label><label>Description<textarea name="description" rows="5" required></textarea></label><label>Payment<select name="reward_type"><option value="bits">BIT$</option><option value="cash">Cash</option></select></label><label>BIT$ reward<input type="number" name="reward_bits" min="0"></label><label>Cash reward<input type="number" step="0.01" name="reward_cash" min="0"></label><button class="bos-btn">Publish task</button></form></section></main><?php bos_page_end(); ?>
